#include<cstdio>
#include<vector>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define Size(v) (int(v.size()))
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline void chkmax(T&x,const T&w){x<w?x=w:T();}
const int N=1e5+10,M=2e5+10,BK=64;int n,m,a[N],k,dis[N],s;
std::vector<int> G[N];int P[N],stk[N],loc[N];bool vis[N];int clr_stk[N],clr_top;
struct node
{
	int idx,dis;inline node(const int &i=0,const int &d=0){idx=i;dis=d;}
	inline bool operator ==(const node&Q){return idx==Q.idx;}
}tmp[N];std::vector<node> dp[N];
inline void DP(const int &u)
{
	std::sort(G[u].begin(),G[u].end(),[&](const int &x,const int &y){return loc[x]<loc[y];});
	int p=0;for(int v:G[u])for(node w:dp[v])tmp[++p]=node(w.idx,w.dis+1);
	std::sort(tmp+1,tmp+p+1,[&](const node&x,const node&y){return x.idx==y.idx?x.dis>y.dis:x.idx<y.idx;});
	p=std::unique(tmp+1,tmp+p+1)-tmp-1;
	std::sort(tmp+1,tmp+p+1,[&](const node&x,const node&y){return x.dis>y.dis;});
	if(p<BK){rep(1,p,i)dp[u].push_back(tmp[i]);dp[u].push_back(node(u,0));}
	else {rep(1,BK,i)dp[u].push_back(tmp[i]);}// while(clr_top)vis[clr_stk[clr_top--]]=false;
}
inline void work(const int &s)
{
	memset(dis,~0x3f,(n+3)<<2);dis[s]=0;
	drep(s,1,u)for(int v: G[u])chkmax(dis[v],dis[u]+1);
}
int main()
{
//	FIN("03-14.in");
	n=read();m=read();int Q=read();
	while(m--){int x=read(),y=read();G[y].push_back(x);}
	rep(1,n,i)DP(i);
	while(Q--)
	{
		s=read();k=read();
		rep(1,k,i)vis[a[i]=read()]=true;
		if(k<BK)
		{
			bool flag=0;
			for(node v:dp[s])if(!vis[v.idx]){flag=1;printf("%d\n",v.dis);break;}
			if(!flag)puts("-1");
		}
		else
		{
			work(s);int mx=-1;
			rep(1,n,i)if(!vis[i]&&dis[i]>=0)chkmax(mx,dis[i]);
			printf("%d\n",mx);
		}
		rep(1,k,i)vis[a[i]]=false;
	}
}
